import React from 'react';
import { JobMonitor } from './JobMonitor';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '28rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Job Monitor</h1>
      <JobMonitor apiUrl="/api/job/status" pollInterval={3000} />
    </div>
  );
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import './styles.css';

interface JobStatus {
  status: 'pending' | 'processing' | 'completed' | 'failed';
  progress: number;
}

interface JobMonitorProps {
  apiUrl: string;
  pollInterval: number;
}

// TODO: Implement polling with start/stop
// 1. Start button begins polling
// 2. Stop button pauses polling
// 3. Auto-stop on terminal state
// 4. Clean up on unmount

export const JobMonitor: React.FC<JobMonitorProps> = ({ apiUrl, pollInterval }) => {
  const [status, setStatus] = useState<JobStatus>({ status: 'pending', progress: 0 });
  const [isPolling, setIsPolling] = useState(false);
  const [pollCount, setPollCount] = useState(0);
  const [lastUpdated, setLastUpdated] = useState<string | null>(null);
  // TODO: interval ref

  // TODO: fetchStatus function
  // TODO: startPolling function
  // TODO: stopPolling function
  // TODO: cleanup on unmount

  const isTerminal = status.status === 'completed' || status.status === 'failed';

  return (
    <div className="jmon">
      <div className="jmon__controls">
        <button
          data-testid="start-btn"
          className="jmon__btn jmon__btn--start"
          disabled={isPolling || isTerminal}
          // TODO: onClick
        >
          Start Polling
        </button>
        <button
          data-testid="stop-btn"
          className="jmon__btn jmon__btn--stop"
          disabled={!isPolling}
          // TODO: onClick
        >
          Stop
        </button>
      </div>

      <div className="jmon__status">
        <span className="jmon__label">Status:</span>
        <span data-testid="status" className={`jmon__value jmon__value--${status.status}`}>
          {status.status}
        </span>
      </div>

      <div className="jmon__progress">
        <div data-testid="progress-bar" className="jmon__bar">
          <div
            className="jmon__fill"
            style={{ width: `${status.progress}%` }}
          />
        </div>
        <span data-testid="progress-value" className="jmon__pct">{status.progress}%</span>
      </div>

      <div className="jmon__meta">
        <span data-testid="last-updated" className="jmon__updated">
          {lastUpdated ? `Updated: ${lastUpdated}` : 'Not started'}
        </span>
        <span data-testid="poll-count" className="jmon__polls">
          Polls: {pollCount}
        </span>
      </div>
    </div>
  );
};

.jmon {
  display: flex;
  flex-direction: column;
  gap: 1rem;
  padding: 1.25rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
}

.jmon__controls {
  display: flex;
  gap: 0.5rem;
}

.jmon__btn {
  padding: 0.375rem 0.75rem;
  border: none;
  border-radius: 0.375rem;
  font-size: 0.8125rem;
  cursor: pointer;
}

.jmon__btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.jmon__btn--start {
  background: #3b82f6;
  color: white;
}

.jmon__btn--stop {
  background: #ef4444;
  color: white;
}

.jmon__status {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.jmon__label {
  font-size: 0.8125rem;
  color: #6b7280;
}

.jmon__value {
  font-weight: 600;
  font-size: 0.875rem;
  text-transform: capitalize;
}

.jmon__value--pending { color: #f59e0b; }
.jmon__value--processing { color: #3b82f6; }
.jmon__value--completed { color: #16a34a; }
.jmon__value--failed { color: #ef4444; }

.jmon__progress {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.jmon__bar {
  flex: 1;
  height: 0.5rem;
  background: #e5e7eb;
  border-radius: 9999px;
  overflow: hidden;
}

.jmon__fill {
  height: 100%;
  background: #3b82f6;
  border-radius: 9999px;
  transition: width 0.3s;
}

.jmon__pct {
  font-size: 0.8125rem;
  font-variant-numeric: tabular-nums;
  color: #374151;
  min-width: 2.5rem;
}

.jmon__meta {
  display: flex;
  justify-content: space-between;
  font-size: 0.75rem;
  color: #9ca3af;
}

