import { render, screen, fireEvent, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

let fetchMock: jest.Mock;
let fetchCallCount: number;

beforeEach(() => {
  jest.useFakeTimers();
  fetchCallCount = 0;
  fetchMock = jest.fn(() => {
    fetchCallCount++;
    const progress = Math.min(fetchCallCount * 25, 100);
    const status = progress >= 100 ? 'completed' : 'processing';
    return Promise.resolve({
      ok: true,
      json: () => Promise.resolve({ status, progress }),
    });
  });
  global.fetch = fetchMock;
});

afterEach(() => {
  jest.useRealTimers();
  jest.restoreAllMocks();
});

import App from './App';

describe('Auto-Polling Status', () => {
  it('renders start and stop buttons', () => {
    render(<App />);
    expect(screen.getByTestId('start-btn')).toBeInTheDocument();
    expect(screen.getByTestId('stop-btn')).toBeInTheDocument();
  });

  it('starts with pending status', () => {
    render(<App />);
    expect(screen.getByTestId('status')).toHaveTextContent('pending');
  });

  it('starts polling on button click', async () => {
    render(<App />);
    await act(async () => {
      fireEvent.click(screen.getByTestId('start-btn'));
    });
    await act(async () => {
      jest.advanceTimersByTime(3000);
    });
    expect(fetchMock).toHaveBeenCalled();
  });

  it('stop button is disabled when not polling', () => {
    render(<App />);
    expect(screen.getByTestId('stop-btn')).toBeDisabled();
  });

  it('poll count increments', async () => {
    render(<App />);
    await act(async () => {
      fireEvent.click(screen.getByTestId('start-btn'));
    });
    await act(async () => {
      jest.advanceTimersByTime(3000);
    });
    const count = parseInt(screen.getByTestId('poll-count').textContent?.match(/\d+/)?.[0] || '0');
    expect(count).toBeGreaterThanOrEqual(1);
  });

  it('progress value updates', async () => {
    render(<App />);
    expect(screen.getByTestId('progress-value')).toHaveTextContent('0%');
    await act(async () => {
      fireEvent.click(screen.getByTestId('start-btn'));
    });
    await act(async () => {
      jest.advanceTimersByTime(3000);
    });
    expect(screen.getByTestId('progress-value').textContent).not.toBe('0%');
  });
});

