import React, { useState, useRef, useCallback, useEffect } from 'react';
import './styles.css';

interface JobStatus {
  status: 'pending' | 'processing' | 'completed' | 'failed';
  progress: number;
}

interface JobMonitorProps {
  apiUrl: string;
  pollInterval: number;
}

export const JobMonitor: React.FC<JobMonitorProps> = ({ apiUrl, pollInterval }) => {
  const [status, setStatus] = useState<JobStatus>({ status: 'pending', progress: 0 });
  const [isPolling, setIsPolling] = useState(false);
  const [pollCount, setPollCount] = useState(0);
  const [lastUpdated, setLastUpdated] = useState<string | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const fetchStatus = useCallback(async () => {
    try {
      const res = await fetch(apiUrl);
      if (!res.ok) return;
      const data: JobStatus = await res.json();
      setStatus(data);
      setPollCount(c => c + 1);
      setLastUpdated(new Date().toLocaleTimeString());

      if (data.status === 'completed' || data.status === 'failed') {
        if (intervalRef.current) {
          clearInterval(intervalRef.current);
          intervalRef.current = null;
        }
        setIsPolling(false);
      }
    } catch {
      // Don't crash on error, just skip this poll
    }
  }, [apiUrl]);

  const startPolling = useCallback(() => {
    setIsPolling(true);
    fetchStatus();
    intervalRef.current = setInterval(fetchStatus, pollInterval);
  }, [fetchStatus, pollInterval]);

  const stopPolling = useCallback(() => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setIsPolling(false);
  }, []);

  useEffect(() => {
    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }
    };
  }, []);

  const isTerminal = status.status === 'completed' || status.status === 'failed';

  return (
    <div className="jmon">
      <div className="jmon__controls">
        <button
          data-testid="start-btn"
          className="jmon__btn jmon__btn--start"
          disabled={isPolling || isTerminal}
          onClick={startPolling}
        >
          Start Polling
        </button>
        <button
          data-testid="stop-btn"
          className="jmon__btn jmon__btn--stop"
          disabled={!isPolling}
          onClick={stopPolling}
        >
          Stop
        </button>
      </div>

      <div className="jmon__status">
        <span className="jmon__label">Status:</span>
        <span data-testid="status" className={`jmon__value jmon__value--${status.status}`}>
          {status.status}
        </span>
      </div>

      <div className="jmon__progress">
        <div data-testid="progress-bar" className="jmon__bar">
          <div className="jmon__fill" style={{ width: `${status.progress}%` }} />
        </div>
        <span data-testid="progress-value" className="jmon__pct">{status.progress}%</span>
      </div>

      <div className="jmon__meta">
        <span data-testid="last-updated" className="jmon__updated">
          {lastUpdated ? `Updated: ${lastUpdated}` : 'Not started'}
        </span>
        <span data-testid="poll-count" className="jmon__polls">
          Polls: {pollCount}
        </span>
      </div>
    </div>
  );
};
